// src/views/user/MyProfile/composables/useModules.js
import { ref, computed } from 'vue'
import { moduleConfig } from '../constants/moduleConfig'
import { BriefcaseIcon } from '@heroicons/vue/24/outline'
import { cityOptions } from '../constants/cityOptions'
import { ElMessage } from 'element-plus'

export function useModules() {
  const activeModules = ref([])
  const currentModule = ref(null)
  const currentItem = ref(null)

  const inactiveModules = computed(() => {
    const activeIds = activeModules.value.map(m => m.id)
    return moduleConfig.filter(m => !activeIds.includes(m.id))
  })

  const editModule = (moduleId, item = null) => {
    currentModule.value = activeModules.value.find(m => m.id === moduleId)
    currentItem.value = item
  }

  const addItem = (moduleId) => {
    currentModule.value = activeModules.value.find(m => m.id === moduleId)
    currentItem.value = null
  }

  const removeModule = (moduleId) => {
    const index = activeModules.value.findIndex(m => m.id === moduleId)
    if (index > -1) {
      activeModules.value.splice(index, 1)
    }
  }

  const activateModule = async (moduleId) => {
    try {
      // 更新布局配置
      const response = await profile.updateLayout({
        [moduleId]: {
          order: getNextOrder(),
          visible: true
        }
      })

      if (response.data?.code === 200) {
        // 从非活动模块移到活动模块
        const moduleIndex = inactiveModules.value.findIndex(m => m.id === moduleId)
        if (moduleIndex > -1) {
          const module = inactiveModules.value[moduleIndex]
          activeModules.value.push(module)
          inactiveModules.value.splice(moduleIndex, 1)
        }
        ElMessage.success('模块添加成功')
      }
    } catch (error) {
      console.error('激活模块失败:', error)
      ElMessage.error('添加模块失败，请重试')
    }
  }

  return {
    activeModules,
    inactiveModules,
    currentModule,
    currentItem,
    editModule,
    addItem,
    removeModule,
    activateModule
  }
}
